   429→    /** This only returns after all input queues are empty. */
   430→    public void waitForInputProcessing() throws Exception {
   431→        while (taskThread.isAlive()) {
   432→            boolean allEmpty = true;
   433→            for (int i = 0; i < numInputGates; i++) {
   434→                if (!inputGates[i].allQueuesEmpty()) {
   435→                    allEmpty = false;
   436→                }
   437→            }
   438→
   439→            if (allEmpty) {
   440→                break;
   441→            }
   442→        }
   443→
   444→        // Wait for all currently available input has been processed.
   445→        final AtomicBoolean allInputProcessed = new AtomicBoolean();
   446→        final MailboxProcessor mailboxProcessor = taskThread.task.mailboxProcessor;
   447→        final MailboxExecutor mailboxExecutor = mailboxProcessor.getMainMailboxExecutor();
   448→        while (taskThread.isAlive()) {
   449→            try {
   450→                final CountDownLatch latch = new CountDownLatch(1);
   451→                mailboxExecutor.execute(
   452→                        () -> {
   453→                            allInputProcessed.set(!mailboxProcessor.isDefaultActionAvailable());
   454→                            latch.countDown();
   455→                        },
   456→                        "query-whether-processInput-has-suspend-itself");
   457→                // Mail could be dropped due to task exception, so we do timed-await here.
   458→                latch.await(1, TimeUnit.SECONDS);
   459→            } catch (RejectedExecutionException ex) {
   460→                // Loop until task thread exit for possible task exception.
   461→            }
   462→
   463→            if (allInputProcessed.get()) {
   464→                break;
   465→            }
   466→
   467→            try {
   468→                Thread.sleep(1);
   469→            } catch (InterruptedException ignored) {
   470→            }
   471→        }
   472→
   473→        Throwable error = taskThread.getError();
   474→        if (error != null) {
   475→            throw new Exception("Exception in the task thread", error);
   476→        }
   477→    }
